'use client';

import type * as React from 'react';

import {cn} from '@/lib/utils';

import {Switch as SwitchPrimitive} from 'radix-ui';

/**
 * A control that allows the user to toggle between checked and not checked.
 *
 * ### Component Props
 *
 * See [Switch props](https://www.radix-ui.com/primitives/docs/components/switch) documentation for full details.
 *
 * | Prop               | Type                           | Default     |
 * | :----------------- | :----------------------------- | :---------- |
 * | _asChild_          | `boolean`                      | `false`     |
 * | _defaultChecked_   | `boolean`                      | -           |
 * | _checked_          | `boolean`                      | -           |
 * | _onCheckedChange_  | `(checked: boolean) => void`   | -           |
 * | _disabled_         | `boolean`                      | -           |
 * | _required_         | `boolean`                      | -           |
 * | _name_             | `string`                       | -           |
 * | _value_            | `string`                       | `"on"`      |
 * | _size_             | `"sm" \| "default" \| "lg"`    | `"default"` |
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <Switch />
 * <Switch size="sm" checked={enabled} onCheckedChange={setEnabled} />
 * ```
 *
 * ### Accessibility (WCAG 2.2 AA)
 *
 * @wcag 4.1.2 Name, Role, Value — semantic `switch` role via Radix Switch primitive.
 * @wcag 2.1.1 Keyboard — toggled via Space key; focusable by default.
 * @wcag 2.4.7 Focus Visible — focus ring applied via `focus-visible:ring-3`.
 */
function Switch({
  className,
  size = 'default',
  ...props
}: React.ComponentProps<typeof SwitchPrimitive.Root> & {
  size?: 'sm' | 'default' | 'lg';
}) {
  return (
    <SwitchPrimitive.Root
      data-slot="switch"
      data-size={size}
      className={cn(
        // base, focus, invalid state
        'peer group/switch relative inline-flex shrink-0 items-center rounded-full border border-transparent transition-all ease-default outline-none',
        'after:absolute after:-inset-x-3 after:-inset-y-2',
        'focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring',
        'aria-invalid:border-destructive aria-invalid:ring-3 aria-invalid:ring-destructive',
        // size variants
        'data-[size=default]:h-[var(--dds-height-switch-thumb)] data-[size=default]:w-8',
        'data-[size=lg]:h-6 data-[size=lg]:w-10',
        'data-[size=sm]:h-3.5 data-[size=sm]:w-6',
        // state
        'data-checked:bg-primary data-unchecked:bg-input data-disabled:cursor-not-allowed data-disabled:opacity-50',
        className
      )}
      {...props}
    >
      <SwitchPrimitive.Thumb
        data-slot="switch-thumb"
        className="pointer-events-none block rounded-full bg-background ring-0 transition-transform ease-default group-data-[size=default]/switch:size-4 group-data-[size=lg]/switch:size-5 group-data-[size=sm]/switch:size-3 group-data-[size=default]/switch:data-checked:translate-x-[calc(100%-2px)] group-data-[size=lg]/switch:data-checked:translate-x-[calc(100%-2px)] group-data-[size=sm]/switch:data-checked:translate-x-[calc(100%-2px)] dark:data-checked:bg-primary-foreground group-data-[size=default]/switch:data-unchecked:translate-x-0 group-data-[size=lg]/switch:data-unchecked:translate-x-0 group-data-[size=sm]/switch:data-unchecked:translate-x-0 dark:data-unchecked:bg-foreground high-contrast:data-unchecked:bg-background"
      />
    </SwitchPrimitive.Root>
  );
}

export {Switch};
